def process(list, fieldName):
    """Find struct with minimum value in a field"""
    if not list or not isinstance(list, (list, tuple)):
        return None, 0.0
    field = str(fieldName or '')
    min_val = None
    min_item = None
    for item in list:
        if isinstance(item, dict) and field in item:
            try:
                val = float(item[field])
                if min_val is None or val < min_val:
                    min_val = val
                    min_item = item
            except (TypeError, ValueError):
                pass
    return min_item, min_val if min_val is not None else 0.0
